ALTER TABLE "knowledge_ingestion_jobs" ADD COLUMN "checkpoint" jsonb;--> statement-breakpoint
ALTER TABLE "knowledge_ingestion_jobs" ADD CONSTRAINT "knowledge_ingestion_jobs_checkpoint_shape_check" CHECK ("knowledge_ingestion_jobs"."checkpoint" IS NULL OR (jsonb_typeof("knowledge_ingestion_jobs"."checkpoint") = 'object' AND octet_length("knowledge_ingestion_jobs"."checkpoint"::text) <= 8192));--> statement-breakpoint
ALTER TABLE "knowledge_ingestion_jobs" ADD CONSTRAINT "knowledge_ingestion_jobs_terminal_checkpoint_check" CHECK ("knowledge_ingestion_jobs"."stage" NOT IN ('published', 'suppressed', 'review_recommended', 'verify_first', 'failed') OR "knowledge_ingestion_jobs"."checkpoint" IS NULL);--> statement-breakpoint
UPDATE "knowledge_ingestion_jobs" SET "checkpoint" = NULL WHERE "stage" IN ('published', 'suppressed', 'review_recommended', 'verify_first', 'failed');--> statement-breakpoint
UPDATE "knowledge_ingestion_jobs" SET "stage" = 'failed', "stage_version" = "stage_version" + 1, "checkpoint" = NULL, "last_error_code" = 'checkpoint_unavailable', "requeue_reason_code" = 'migration_checkpoint_unavailable', "claimed_by" = NULL, "claimed_at" = NULL, "lease_expires_at" = NULL, "fencing_token" = NULL, "updated_at" = timezone('UTC', now()) WHERE "stage" IN ('triaging', 'extracting', 'judging', 'relating') AND "checkpoint" IS NULL;
